module mux_16bit (
    input [15:0][15:0] in,
    input [3:0] sel,
    output reg [15:0] obf_out
);

always @(*) begin
    case(sel)
        4'b0000: obf_out = in[0];
        4'b0001: obf_out = in[1];
        4'b0010: obf_out = in[2];
        4'b0011: obf_out = in[3];
        4'b0100: obf_out = in[4];
        4'b0101: obf_out = in[5];
        4'b0110: obf_out = in[6];
        4'b0111: obf_out = in[7];
        4'b1000: obf_out = in[8];
        4'b1001: obf_out = in[9];
        4'b1010: obf_out = in[10];
        4'b1011: obf_out = in[11];
        4'b1100: obf_out = in[12];
        4'b1101: obf_out = in[13];
        4'b1110: obf_out = in[14];
        4'b1111: obf_out = in[15];
        default: obf_out = 16'b0;
    endcase
end

endmodule
